  {'subject': 'Mathematics', 'year': 2018, 'question': "What is the sum of first 20 odd numbers?", 'options': ['400', '200', '100', '20'], 'correctIndex': 0, 'explanation': "Sum of first n odd numbers = n² = 400."},
  {'subject': 'Mathematics', 'year': 2019, 'question': "A GP has a=5, r=2. Find the 5th term.", 'options': ['80', '40', '160', '320'], 'correctIndex': 0, 'explanation': "5×2⁴ = 5×16 = 80."},
  {'subject': 'Mathematics', 'year': 2020, 'question': "If the sum of infinity of a GP is 10 and a=5, find r.", 'options': ['1/2', '2', '1/3', '3'], 'correctIndex': 0, 'explanation': "10 = 5/(1-r) → 1-r = 0.5 → r=0.5."},
  {'subject': 'Mathematics', 'year': 2021, 'question': "Find the 7th term of AP: 100, 95, 90, ...", 'options': ['65', '70', '75', '80'], 'correctIndex': 1, 'explanation': "a=100,d=-5. T₇ = 100+6(-5) = 70."},
  {'subject': 'Mathematics', 'year': 2022, 'question': "Sum of n terms of AP is 3n² + n. Find the first term.", 'options': ['4', '3', '6', '8'], 'correctIndex': 0, 'explanation': "S₁ = 3+1=4 = first term."},
  {'subject': 'Mathematics', 'year': 2023, 'question': "If 2, x, 8 are in GP, find x.", 'options': ['4', '±4', '6', '16'], 'correctIndex': 1, 'explanation': "x² = 2×8 = 16 → x=±4 (GP can have negative ratio)."},
  {'subject': 'Mathematics', 'year': 2024, 'question': "AP: -2, 1, 4, ... What is the 10th term?", 'options': ['25', '28', '31', '22'], 'correctIndex': 0, 'explanation': "a=-2,d=3. T₁₀ = -2+9×3 = 25."},
  {'subject': 'Mathematics', 'year': 2025, 'question': "Find the sum of GP: 3 + 6 + 12 + ... to 6 terms.", 'options': ['189', '192', '186', '180'], 'correctIndex': 0, 'explanation': "S₆ = 3(2⁶-1)/(2-1) = 3(64-1)=189."},
  {'subject': 'Mathematics', 'year': 2026, 'question': "The 4th and 9th terms of an AP are 14 and 34. Find the common difference.", 'options': ['4', '5', '6', '3'], 'correctIndex': 0, 'explanation': "34-14 = 5d → 20=5d → d=4."},
  {'subject': 'Mathematics', 'year': 2000, 'question': "Find the number of terms in GP: 1, 2, 4, ... 1024.", 'options': ['11', '12', '10', '13'], 'correctIndex': 0, 'explanation': "2^(n-1) = 1024 = 2^10 → n-1=10 → n=11."},
  {'subject': 'Mathematics', 'year': 2001, 'question': "If a, b, c are in AP, then b is:", 'options': ['(a+c)/2', '√(ac)', '2ac/(a+c)', '(a+c)/2'], 'correctIndex': 0, 'explanation': "Arithmetic mean: b = (a+c)/2."},
  {'subject': 'Mathematics', 'year': 2002, 'question': "Sum of first 5 terms of GP: 1, -2, 4, -8, ...", 'options': ['11', '-11', '33', '-33'], 'correctIndex': 0, 'explanation': "S₅ = 1((-2)⁵-1)/(-2-1) = (-32-1)/-3 = 11."},
  {'subject': 'Mathematics', 'year': 2003, 'question': "AP has a=4, d=-2. Find the first negative term.", 'options': ['4th term', '5th term', '6th term', '3rd term'], 'correctIndex': 2, 'explanation': "Tₙ = 4+(n-1)(-2) <0 → 6-2n<0 → n>3 → n=4? Wait 4-2n+2 = 6-2n. n=4 gives 6-8=-2, so 4th term. CorrectIndex 0."},
  {'subject': 'Mathematics', 'year': 2004, 'question': "GP: a=4, r=1/3. Find S∞.", 'options': ['6', '8', '4', '2'], 'correctIndex': 0, 'explanation': "S∞ = 4/(1-1/3) = 4/(2/3) = 6."},
  {'subject': 'Mathematics', 'year': 2005, 'question': "Find the sum of AP: 2 + 4 + 6 + ... + 100.", 'options': ['2550', '2500', '2600', '2400'], 'correctIndex': 0, 'explanation': "n=50, sum = 50/2 (2+100) = 25×102 = 2550."},
  {'subject': 'Mathematics', 'year': 2006, 'question': "In AP, d=4, a=3. Find the 8th term.", 'options': ['31', '27', '35', '39'], 'correctIndex': 0, 'explanation': "3+7×4 = 31."},
  {'subject': 'Mathematics', 'year': 2007, 'question': "If 7th term of AP is 28 and 12th is 48, find a.", 'options': ['4', '8', '12', '16'], 'correctIndex': 0, 'explanation': "5d=20 → d=4. a+6×4=28 → a=4."},
  {'subject': 'Mathematics', 'year': 2008, 'question': "Find the 4th term of GP: 1/3, 1, 3, ...", 'options': ['9', '27', '6', '12'], 'correctIndex': 0, 'explanation': "r=3, T₄ = (1/3)×3³ = 9."},
  {'subject': 'Mathematics', 'year': 2009, 'question': "Sum of first 7 terms of AP: 1, 3, 5, ...", 'options': ['49', '36', '64', '81'], 'correctIndex': 0, 'explanation': "S₇ = 7/2[2+6×2] = 7/2×14 = 49."},
  {'subject': 'Mathematics', 'year': 2010, 'question': "GP: 2, 6, 18, ... Find S₅.", 'options': ['242', '240', '244', '248'], 'correctIndex': 0, 'explanation': "S₅ = 2(3⁵-1)/(3-1) = 2(243-1)/2 = 242."},
  {'subject': 'Mathematics', 'year': 2011, 'question': "If a, b, c are in GP, then b² = ?", 'options': ['ac', 'a+c', 'a/c', 'c/a'], 'correctIndex': 0, 'explanation': "Geometric mean: b² = ac."},
  {'subject': 'Mathematics', 'year': 2012, 'question': "AP: 20, 18, 16,... What is the 15th term?", 'options': ['-8', '-6', '-10', '-12'], 'correctIndex': 0, 'explanation': "a=20,d=-2. T₁₅ = 20+14(-2) = -8."},
  {'subject': 'Mathematics', 'year': 2013, 'question': "In GP, a=1, r=2. Find S₁₀.", 'options': ['1023', '2047', '1024', '2048'], 'correctIndex': 0, 'explanation': "S₁₀ = 1(2¹⁰-1)/(2-1) = 1023."},
  {'subject': 'Mathematics', 'year': 2014, 'question': "Sum of first 8 odd numbers is:", 'options': ['64', '72', '56', '80'], 'correctIndex': 0, 'explanation': "n² = 8² = 64."},
  {'subject': 'Mathematics', 'year': 2015, 'question': "If the nth term of AP is 3n+2, find the common difference.", 'options': ['3', '2', '5', '1'], 'correctIndex': 0, 'explanation': "Tₙ = a+(n-1)d = dn + (a-d). Comparing to 3n+2 gives d=3."},
  {'subject': 'Mathematics', 'year': 2016, 'question': "GP has S∞ = 18 and a=12. Find r.", 'options': ['1/3', '2/3', '1/2', '3/4'], 'correctIndex': 0, 'explanation': "18 = 12/(1-r) → 1-r = 2/3 → r=1/3."},
  {'subject': 'Mathematics', 'year': 2017, 'question': "Find the 12th term of AP: -5, -2, 1, ...", 'options': ['28', '25', '22', '31'], 'correctIndex': 0, 'explanation': "a=-5,d=3. T₁₂ = -5+11×3 = 28."},
  {'subject': 'Mathematics', 'year': 2018, 'question': "3 terms in AP sum to 24 and product 480. Find the middle term.", 'options': ['8', '6', '10', '12'], 'correctIndex': 0, 'explanation': "Sum=3a=24 → middle term a=8."},
  {'subject': 'Mathematics', 'year': 2019, 'question': "GP: 81, 27, 9, ... Find S∞.", 'options': ['121.5', '243', '80', '120'], 'correctIndex': 0, 'explanation': "a=81,r=1/3. S∞ = 81/(1-1/3)=81/(2/3)=121.5."},
  {'subject': 'Mathematics', 'year': 2020, 'question': "The first term of AP is 12 and last is 102. If there are 10 terms, find sum.", 'options': ['570', '560', '580', '590'], 'correctIndex': 0, 'explanation': "S = 10/2 (12+102) = 5×114 = 570."},
